import { describe, expect, test } from '@a0n/gnosis/test';
import {
  fibZWeights,
  GNOSIS_MATH_SANDBOX_INTEGRATION_CANDIDATES,
  GNOSIS_MATH_SANDBOX_LEAN_MODULES,
  KRAFT_ADDRESS_SPACE_LEAN_MODULE,
  MATH_SANDBOX_SCRIPT_DISCLAIMER,
  kraftSumFloat,
} from '../math-sandbox';

describe('math-sandbox anchors', () => {
  test('exposes Lean module anchors', () => {
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES).toContain('MathSandbox');
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.GnosisMathPrelude',
    );
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.Hyperoperations',
    );
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES).toContain('ForkRaceFoldTheorems.GnosisMath.Basic');
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES).toContain(
      'ForkRaceFoldTheorems.GreekLogicCanon.DiscreteBoundary',
    );
    expect(GNOSIS_MATH_SANDBOX_LEAN_MODULES.length).toBeGreaterThanOrEqual(10);
  });

  test('lists integration candidates including GreekLogicCanon fork target', () => {
    expect(GNOSIS_MATH_SANDBOX_INTEGRATION_CANDIDATES).toContain(
      'ForkRaceFoldTheorems.GreekLogicCanon',
    );
    expect(GNOSIS_MATH_SANDBOX_INTEGRATION_CANDIDATES).toContain(
      'ForkRaceFoldTheorems.PisotVickreyTable',
    );
  });

  test('disclaimer is explicit', () => {
    expect(MATH_SANDBOX_SCRIPT_DISCLAIMER.length).toBeGreaterThan(30);
    expect(MATH_SANDBOX_SCRIPT_DISCLAIMER).toContain('Lean');
  });

  test('kraftSumFloat matches binary single-bit Kraft 1/2 + 1/2', () => {
    expect(kraftSumFloat(2, [1, 1])).toBeCloseTo(1);
  });

  test('kraftSumFloat: balanced length-2 quaternary code hits Kraft = 1 (toy)', () => {
    expect(kraftSumFloat(2, [2, 2, 2, 2])).toBeCloseTo(1);
  });

  test('Kraft module anchor points at KraftInequality', () => {
    expect(KRAFT_ADDRESS_SPACE_LEAN_MODULE).toContain('KraftInequality');
  });

  test('fibZWeights matches Lean fibZ/F head (1,1,2,…,34 for index 8)', () => {
    expect(fibZWeights(0)).toEqual([]);
    expect(fibZWeights(9)).toEqual([1, 1, 2, 3, 5, 8, 13, 21, 34]);
  });
});
